import React, { useState, useEffect } from "react";
import "./index.css";
import { BrowserRouter } from 'react-router-dom';
import backgroundImg from "./background.jpg";
import loginBackgroundImg from "./login-background.jfif";
import createBackgroundImg from "./create-background.jpg";
import aboutBackgroundImg from "./about-background.jpg";
import contactBackgroundImg from "./contact-background.jpg";
import selectBackgroundImg from "./select-background.jpg"; 
import discoveryBackgroundImg from './firstpage.jpg'; // Import the background image
import ListenerImage from './Listener.png';  
import ArtistImage from './Artist.png';  
import userRepository from "./UserRepository";
import AuthService from "./AuthService";
import handleApiError from './handleApiError';

function App() {
  const [currentPage, setCurrentPage] = useState("home");
  const [userData, setUserData] = useState({
    fullName: "",
    email: "",
    password: "",
    accountType: "",
    genre: "",
    influencedArtists: [],
    likedArtists: []
  });

  const navigateTo = (page) => {
    setCurrentPage(page);
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setUserData({
      ...userData,
      [name]: value
    });
  };

  const handleFormSubmit = (e) => {
    e.preventDefault();
    if (currentPage === "createAccount") {
      navigateTo("accountType");
    }
  };

  const handleAccountTypeSubmit = (e) => {
    e.preventDefault();
    if (userData.accountType === "artist" && userData.genre && userData.influencedArtists.length === 3) {
      navigateTo("home");
    } else if (userData.accountType === "listener" && userData.likedArtists.length === 3) {
      navigateTo("home");
    } else {
      alert("Please fill all required fields.");
    }
  };

  const Home = () => (
    <div
      className="home-container"
      style={{ backgroundImage: `url(${backgroundImg})` }}
    >
      <div className="left-section">
        <nav className="navbar">
          <button className="nav-button" onClick={() => navigateTo("home")}>
            Home
          </button>
          <button className="nav-button" onClick={() => navigateTo("about")}>
            About
          </button>
          <button className="nav-button" onClick={() => navigateTo("contact")}>
            Contact
          </button>
          <button className="nav-button" onClick={() => navigateTo("login")}>
            Login
          </button>
        </nav>
        <div className="content">
          <h1 className="title">Welcome to SoundWake</h1>
          <p className="description">
            We bring the underground to you. Discover new upcoming independent artists, create playlists
          </p>
          <p className="description">and share your experience with friends.</p>
        </div>
      </div>
    </div>
  );

  const AccountType = () => {
    const usr = userRepository.getUser();
    if (!usr || !usr.email) {
      return <div>Error: User is not logged in</div>; // Handle error if user is not found
    }
  
    const email = usr.email;
  
    const handleAccountTypeSubmit = async (type) => {
      if(type == "Artist")
        userRepository.setUser({ accountType: 'artist' });
      else
        userRepository.setUser({ accountType: 'listener' });
      const button = document.getElementById(type);
      if (button) button.disabled = true;
  
      try {
        const response = await fetch("http://localhost:8080/add-account-type", {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify({ email, accountType: type }),
        });
  
        console.log("Status Code:", response.status);
        console.log("Response Headers:", response.headers);
  
        const rawText = await response.text();
        console.log("Raw Response Text:", rawText);
  
        if (response.ok) {
          try {
            const jsonData = JSON.parse(rawText);
            console.log("Parsed Data:", jsonData);

            if (jsonData.message) {
              console.log(`${type} added successfully`, jsonData);
              navigateTo("genre");
            }
          } catch (error) {
            console.error("Error parsing JSON:", error, "Raw Data:", rawText);
            alert(`Error: Could not parse response as JSON. ${error.message}`);
          }
        } else {
          console.error("Failed to add account type. Response not ok:", response.statusText);
          alert(`Error: Failed to add account type. Status: ${response.statusText}`);
        }
      } catch (error) {
        console.error("Error during fetch:", error);
        alert(`Error: ${error.message}`);
      } finally {
        if (button) button.disabled = false;
      }
    };
  
    return (
      <div
        style={{
          display: "flex",
          flexDirection: "column",
          justifyContent: "center",
          alignItems: "center",
          height: "100vh",
          backgroundImage: `url(${selectBackgroundImg})`,
          backgroundSize: "cover",
          backgroundPosition: "center",
          textAlign: "center",
        }}
      >
        {/* Title */}
        <h2 style={{ marginBottom: "40px", color: "white", fontSize: "28px" }}>
          Choose an account type (Listener or Artist)
        </h2>
  
        {/* Buttons */}
        <div
          style={{
            display: "flex",
            justifyContent: "space-between",
            width: "60%", // Adjust width to make sure the buttons fit well
            gap: "20px", // Add spacing between the buttons
          }}
        >
          <button
            id="Listener"
            style={{
              width: "300px", // 2x bigger button size
              height: "300px", // 2x bigger button size to make them square
              border: "none",
              background: "transparent",
              cursor: "pointer",
              transition: "transform 0.3s ease",
              display: "flex", // Center the image inside the button
              justifyContent: "center",
              alignItems: "center",
              borderRadius: "10px", // Optional: adds rounded corners to buttons
            }}
            onClick={() => handleAccountTypeSubmit("Listener")}
            onMouseOver={(e) => (e.currentTarget.style.transform = "scale(1.05)")}
            onMouseOut={(e) => (e.currentTarget.style.transform = "scale(1)")}
          >
            <img
              src={ListenerImage}
              alt="Listener"
              style={{
                width: "100%", // Make image fill the button's size
                height: "100%",
                objectFit: "cover", // Force image to cover the button area, making it square
                borderRadius: "10px", // Optional: rounds the image corners to match button
              }}
            />
          </button>
  
          <button
            id="Artist"
            style={{
              width: "300px", // 2x bigger button size
              height: "300px", // 2x bigger button size to make them square
              border: "none",
              background: "transparent",
              cursor: "pointer",
              transition: "transform 0.3s ease",
              display: "flex", // Center the image inside the button
              justifyContent: "center",
              alignItems: "center",
              borderRadius: "10px", // Optional: adds rounded corners to buttons
            }}
            onClick={() => handleAccountTypeSubmit("Artist")}
            onMouseOver={(e) => (e.currentTarget.style.transform = "scale(1.05)")}
            onMouseOut={(e) => (e.currentTarget.style.transform = "scale(1)")}
          >
            <img
              src={ArtistImage}
              alt="Artist"
              style={{
                width: "100%", // Make image fill the button's size
                height: "100%",
                objectFit: "cover", // Force image to cover the button area, making it square
                borderRadius: "10px", // Optional: rounds the image corners to match button
              }}
            />
          </button>
        </div>
      </div>
    );
  };

    const DiscoveryPage = () => {
        const [searchQuery, setSearchQuery] = useState('');
        const [filters, setFilters] = useState({ genre: '', location: '', popularity: '' });
        const [orderBy, setOrderBy] = useState('name'); // Default ordering by name
        const [artists, setArtists] = useState([]);

        const handleBackToUserMain = () => {
            navigateTo("userMain");
        };

        const handleSearchChange = (e) => {
            setSearchQuery(e.target.value);
        };

        const handleFilterChange = (e) => {
            setFilters({ ...filters, [e.target.name]: e.target.value });
        };

        const handleOrderChange = (e) => {
            setOrderBy(e.target.value);
        };

        const handleSearchSubmit = async (e) => {
            e.preventDefault();

            // Prepare the query parameters for the backend request
            const params = {
                searchQuery,
                genre: filters.genre,
                location: filters.location,
                popularity: filters.popularity,
                orderBy,
            };

            try {
                const response = await fetch('http://localhost:8080/artist/search', {
                    method: 'GET',
                    headers: { 'Content-Type': 'application/json' },
                    // Convert the parameters to a query string
                    body: JSON.stringify(params),
                });

                if (response.ok) {
                    const data = await response.json();
                    setArtists(data); // Set the artists data from the response
                } else {
                    console.error('Error during search:', response.statusText);
                }
            } catch (error) {
                console.error('Error during search:', error);
            }
        };

        return (
            <div className="discovery-container">
                {/* Other existing styles... */}

                <h1>Discovery Page</h1>

                {/* Search Input */}
                <div>
                    <input
                        type="text"
                        value={searchQuery}
                        onChange={handleSearchChange}
                        placeholder="Search artists"
                    />
                </div>

                {/* Filters */}
                <div>
                    <select name="genre" value={filters.genre} onChange={handleFilterChange}>
                        <option value="">Select Genre</option>
                        <option value="pop">Pop</option>
                        <option value="rock">Rock</option>
                        <option value="hiphop">Hip Hop</option>
                        {/* Add more genres as needed */}
                    </select>

                    <select name="location" value={filters.location} onChange={handleFilterChange}>
                        <option value="">Select Location</option>
                        <option value="usa">USA</option>
                        <option value="uk">UK</option>
                        <option value="canada">Canada</option>
                        {/* Add more locations as needed */}
                    </select>

                    <select name="popularity" value={filters.popularity} onChange={handleFilterChange}>
                        <option value="">Select Popularity</option>
                        <option value="high">High</option>
                        <option value="medium">Medium</option>
                        <option value="low">Low</option>
                    </select>

                    <select name="orderBy" value={orderBy} onChange={handleOrderChange}>
                        <option value="name">Order by Name</option>
                        <option value="popularity">Order by Popularity</option>
                        <option value="location">Order by Location</option>
                    </select>
                </div>

                {/* Search Button */}
                <button onClick={handleSearchSubmit}>Search</button>

                {/* Displaying Results */}
                <div>
                    {artists.length > 0 ? (
                        artists.map((artist) => (
                            <div key={artist.id}>
                                <h3>{artist.name}</h3>
                                <p>{artist.genre}</p>
                                <p>{artist.location}</p>
                                <p>{artist.popularity}</p>
                            </div>
                        ))
                    ) : (
                        <p>No artists found.</p>
                    )}
                </div>
            </div>
        );
    };
  

  const ArtistPage = () => {
    const [artist, setArtist] = useState(null);
    const fullName = userRepository.getFullName();

    useEffect(() => {
      const fetchArtistData = async () => {
        try {
          const response = await fetch(`http://localhost:8080/users/fullName/${fullName}`);
          const data = await response.json();

          if (data.error) {
            console.error(data.error);
            return;
          }

          setArtist(data);
        } catch (error) {
          console.error('Error fetching artist data:', error);
        }
      };

      if (fullName) {
        fetchArtistData();
      } else {
        console.log('No artist name found');
      }
    }, [fullName]);

    const handleBackToDiscovery = () => {
      navigateTo("discovery");
    };

    if (!artist) {
      return <div>Loading artist details...</div>;
    }
  
    return (
      <div
        className="artist-container"
        style={{
          backgroundImage: `url(${artist.wallpaperPath || '/default-wallpaper.jpg'})`,
          backgroundSize: 'cover',
          backgroundRepeat: 'no-repeat',
          backgroundPosition: 'center',
          height: '100vh',
          width: '100vw',
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'center',
          color: 'white',
          textAlign: 'center',
          position: 'relative',
          boxSizing: 'border-box',
        }}
      >
        {/* Overlay */}
        <div
          style={{
            position: 'absolute',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            backgroundColor: 'rgba(0, 0, 0, 0.5)', // Dark overlay
            zIndex: 1,
          }}
        />
  
        {/* Back to Discovery Button */}
        <button
          onClick={handleBackToDiscovery}
          style={{
            position: 'absolute',
            top: '20px',
            left: '20px',
            padding: '12px 25px',
            backgroundColor: 'rgba(0, 0, 0, 0.7)',
            color: 'white',
            border: 'none',
            borderRadius: '5px',
            fontSize: '1rem',
            cursor: 'pointer',
            zIndex: 2,
            transition: 'all 0.3s ease',
          }}
        >
          Back to Discovery
        </button>
  
        {/* Artist Info */}
        <div style={{ zIndex: 2, display: 'flex', alignItems: 'center' }}>
          <img
            src={artist.imagePath}
            alt="Artist Icon"
            style={{
              width: '150px',
              height: '150px',
              objectFit: 'cover',
              borderRadius: '50%',
              marginRight: '20px',
            }}
          />
          <div>
            <h1>{artist.fullName}</h1>
            <p>{artist.description}</p>
          </div>
        </div>
      </div>
    );
  };

  const Genre = () => {
    const [genres, setGenres] = useState([]);
    const [userType, setUserType] = useState("");
  
    const usr = userRepository.getUser();
  
    useEffect(() => {
      if (usr && usr.accountType) {
        setUserType(usr.accountType);
      }
    }, [usr]);
  
    useEffect(() => {
      const fetchGenres = async () => {
        try {
          const response = await fetch("http://localhost:8080/genres");
          if (response.ok) {
            const data = await response.json();
            setGenres(data);
          } else {
            console.error("Failed to fetch genres.");
          }
        } catch (error) {
          console.error("Error fetching genres:", error);
        }
      };
  
      fetchGenres();
    }, []);
  
    const handleGenreSelect = async (genre) => {
      try {
          if (userType === "artist" && usr && usr.email) {
              const response = await fetch("http://localhost:8080/update-genre", {
                  method: "POST",
                  headers: {
                      "Content-Type": "application/json",
                  },
                  body: JSON.stringify({
                      email: usr.email,
                      genreId: genre.id,
                  }),
              });

              if (response.ok) {
                  console.log("Genre updated successfully");
                  navigateTo("influences");
              } else {
                  console.error("Failed to update genre.");
              }
          }
      } catch (error) {
        console.error("Error selecting genre:", error);
      }
    };
  
    const middleIndex = Math.ceil(genres.length / 2);
    const topRow = genres.slice(0, middleIndex);
    const bottomRow = genres.slice(middleIndex);
  
    return (
      <div
        className="genre-container"
        style={{
          backgroundImage: `url(${selectBackgroundImg})`,
          backgroundSize: "cover",
          backgroundPosition: "center",
          padding: "20px",
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
          justifyContent: "center",
          minHeight: "100vh",
        }}
      >
        <h1
          style={{
            color: "white",
            fontSize: "36px",
            fontWeight: "bold",
            marginBottom: "20px",
          }}
        >
          Choose a genre
        </h1>
  
        {[topRow, bottomRow].map((row, rowIndex) => (
          <div
            key={rowIndex}
            style={{
              display: "flex",
              justifyContent: "center",
              gap: "20px",
              marginBottom: rowIndex === 0 ? "40px" : "0",
            }}
          >
            {row.map((genre) => (
              <button
                key={genre.id}
                className="genre-button"
                style={{
                  backgroundImage: `url(${genre.imagePath})`,
                  backgroundSize: "cover",
                  backgroundPosition: "center",
                  width: "200px",
                  height: "200px",
                  border: "none",
                  borderRadius: "10px",
                  cursor: "pointer",
                  transition: "transform 0.3s ease",
                }}
                onClick={() => handleGenreSelect(genre)}
                onMouseOver={(e) => (e.currentTarget.style.transform = "scale(1.1)")}
                onMouseOut={(e) => (e.currentTarget.style.transform = "scale(1)")}
              ></button>
            ))}
          </div>
        ))}
      </div>
    );
  };
  

  const Contact = () => {
    const [fullName, setFullName] = useState("");
    const [email, setEmail] = useState("");
    const [message, setMessage] = useState("");
  
    const handleFullNameChange = (event) => {
      setFullName(event.target.value);
    };
  
    const handleEmailChange = (event) => {
      setEmail(event.target.value);
    };
  
    const handleMessageChange = (event) => {
      setMessage(event.target.value);
    };
  
    return (
      <div
        className="contact-container"
        style={{ backgroundImage: `url(${contactBackgroundImg})` }}
      >
        <nav className="navbar-contact">
          <button className="nav-button" onClick={() => navigateTo("home")}>
            Home
          </button>
          <button className="nav-button" onClick={() => navigateTo("about")}>
            About
          </button>
          <button className="nav-button" onClick={() => navigateTo("contact")}>
            Contact
          </button>
          <button className="nav-button" onClick={() => navigateTo("login")}>
            Login
          </button>
        </nav>
  
        <div className="contact-content">
          {/* Left Section */}
          <div className="contact-left">
            <h1>Tell Us About Your Experience</h1>
            <p>
              We'd love to hear your thoughts! Connect with us on social media or
              fill out the contact form to share your feedback.
            </p>
            <div className="social-icons">
              <a href="https://facebook.com" target="_blank" rel="noopener noreferrer">
                <img src="/facebook.png" alt="Facebook" />
              </a>
              <a href="https://instagram.com" target="_blank" rel="noopener noreferrer">
                <img src="/instagram.png" alt="Instagram" />
              </a>
            </div>
          </div>
  
          {/* Right Section */}
          <div className="contact-form-container">
            <h2>Contact Form</h2>
            <form>
              <input
                type="text"
                placeholder="Full Name"
                value={fullName}
                onChange={handleFullNameChange}
                required
              />
              <input
                type="email"
                placeholder="Email"
                value={email}
                onChange={handleEmailChange}
                required
              />
              <textarea
                placeholder="Message"
                value={message}
                onChange={handleMessageChange}
                required
              ></textarea>
              <button type="submit">Submit</button>
            </form>
          </div>
        </div>
      </div>
    );
  };

  const About = () => (
    <div
      className="about-container"
      style={{ backgroundImage: `url(${aboutBackgroundImg})` }}
    >
      <nav className="navbar-about">
        <button className="nav-about-button" onClick={() => navigateTo("home")}>
          Home
        </button>
        <button className="nav-about-button" onClick={() => navigateTo("about")}>
          About
        </button>
        <button className="nav-about-button" onClick={() => navigateTo("contact")}>
          Contact
        </button>
        <button className="nav-about-button" onClick={() => navigateTo("login")}>
          Login
        </button>
      </nav>
      <div className="about-text">
        <h1>About SoundWake</h1>
        <p>
          SoundWake is your ultimate destination for discovering new music and
          creating personalized playlists. Whether you're exploring new genres or
          revisiting old favorites, SoundWake helps you connect with music in a
          whole new way.
        </p>
        <p>
          Share your playlists with friends, discover curated collections, and
          let SoundWake be the soundtrack to your life. Join a community of
          music lovers and start your journey with us today.
        </p>
      </div>
    </div>
  );

    const Login = () => {
        const [email, setEmail] = useState('');
        const [password, setPassword] = useState('');
        const [error, setError] = useState(''); // To handle error messages

        const handleEmailChange = (event) => {
            setEmail(event.target.value);
        };

        const handlePasswordChange = (event) => {
            setPassword(event.target.value);
        };

        const handleLoginSubmit = async (e) => {
            e.preventDefault();
            try {
                const response = await AuthService.login(email, password);

                if (response && response.userId) {
                    userRepository.setUser(response);
                    console.log("Logged in user:", response);

                    navigateTo("userMain");
                } else {
                    setError('Invalid credentials or user not found');
                }
            } catch (error) {
                handleApiError(error);
            }
        };

        return (
            <div
                className="login-container"
                style={{ backgroundImage: `url(${loginBackgroundImg})`, backgroundSize: 'cover', backgroundPosition: 'center' }}
            >
                <div className="login-form-container">
                    <h1>Login</h1>
                    <form onSubmit={handleLoginSubmit}>
                        <input
                            type="email"
                            placeholder="Email"
                            value={email}
                            onChange={handleEmailChange}
                            required
                        />
                        <input
                            type="password"
                            placeholder="Password"
                            value={password}
                            onChange={handlePasswordChange}
                            required
                        />
                        <button type="submit">Login</button>
                    </form>
                    {error && <p className="error-message">{error}</p>} {/* Display error message if login fails */}
                    <button onClick={() => navigateTo('home')} className="back-button">
                        Back to Home
                    </button>
                    <p className="create-account-option">
                        Don't have an account yet?{" "}
                        <span
                            className="create-account-link"
                            onClick={() => navigateTo('createAccount')}
                        >
            Create one
          </span>
                    </p>
                </div>
            </div>
        );
    };



    const CreateAccount = () => {
        const [fullName, setFullName] = useState("");
        const [email, setEmail] = useState("");
        const [password, setPassword] = useState("");

        const handleFullNameChange = (event) => setFullName(event.target.value);
        const handleEmailChange = (event) => setEmail(event.target.value);
        const handlePasswordChange = (event) => setPassword(event.target.value);

        const handleSubmit = (event) => {
            event.preventDefault();

            fetch("http://localhost:8080/create-account", {
                method: "POST",
                headers: {
                    "Content-Type": "application/json",
                },
                body: JSON.stringify({ fullName, email, password }),
            })
                .then((response) => {
                    if (!response.ok) {
                        throw new Error("Failed to create account");
                    }
                    return response.json();
                })
                .then((data) => {
                    // Assuming the response contains the full user data including userId
                    const { userId, fullName, email } = data; // This may change based on your API response
                    userRepository.setUser({ userId, fullName, email, password });

                    console.log("User created successfully:", data);

                    navigateTo("accountType");
                })
                .catch((error) => {
                    handleApiError(error);
                });
        };

        return (
            <div className="create-container" style={{ backgroundImage: `url(${createBackgroundImg})` }}>
                <div className="create-form-container">
                    <h1>Create Account</h1>
                    <form onSubmit={handleSubmit}>
                        <input
                            type="text"
                            placeholder="Full Name"
                            value={fullName}
                            onChange={handleFullNameChange}
                            required
                        />
                        <input
                            type="email"
                            placeholder="Email"
                            value={email}
                            onChange={handleEmailChange}
                            required
                        />
                        <input
                            type="password"
                            placeholder="Password"
                            value={password}
                            onChange={handlePasswordChange}
                            required
                        />
                        <button type="submit">Sign Up</button>
                    </form>
                    <button onClick={() => navigateTo("login")} className="back-button">
                        Back
                    </button>
                </div>
            </div>
        );
    };


    const InfluencesPage = () => {
        const [genres, setGenres] = useState([]);
        const [selectedCount, setSelectedCount] = useState(0);
        const [artists, setArtists] = useState([]);
        const [currentArtistId, setCurrentArtistId] = useState(null);
        const [selectedGenreId, setSelectedGenreId] = useState(null);
        const [selectedArtistId, setSelectedArtistId] = useState(null);

        const usr = userRepository.getUser();

        // Fetch genres on load
        useEffect(() => {
            const fetchGenres = async () => {
                try {
                    const response = await fetch("http://localhost:8080/genres");
                    const data = await response.json();
                    setGenres(data);
                } catch (err) {
                    console.error("Failed to fetch genres", err);
                }
            };

            const fetchCurrentArtistId = async () => {
                if (usr?.userId) {
                    console.log("User ID:", usr.userId); // Log user ID
                    try {
                        const response = await fetch(`http://localhost:8080/artists/user/${usr.userId}`);
                        const data = await response.json();
                        setCurrentArtistId(data.artistId);
                        console.log("Current Artist ID fetched:", data.artistId); // Log currentArtistId
                    } catch (err) {
                        console.error("Failed to fetch artist for user", err);
                    }
                } else {
                    console.log("No user ID found!"); // Log if no user ID
                }
            };

            fetchGenres();
            fetchCurrentArtistId();
        }, [usr]);

        const handleGenreClick = async (genreId) => {
            try {
                const response = await fetch(`http://localhost:8080/artists/genre/${genreId}`);
                if (response.ok) {
                    const data = await response.json();
                    setArtists(data);
                    setSelectedGenreId(genreId); // Set selected genre id
                }
            } catch (err) {
                console.error("Failed to fetch artists by genre", err);
            }
        };

        const handleArtistClick = async (userId) => {
            console.log("Artist button clicked! Current Artist ID:", currentArtistId, "Influenced By ID:", userId);

            if (!currentArtistId || selectedCount >= 3) return;

            // Fetch the artistId for the given userId first
            try {
                const response = await fetch(`http://localhost:8080/artists/user/${userId}`);

                if (!response.ok) {
                    console.error("Failed to fetch artist for userId:", userId);
                    return;
                }

                const artistData = await response.json();
                const artistId = artistData.artistId; // Assuming the response contains artistId

                // Proceed to create the influence between currentArtistId and the fetched artistId
                console.log("Sending influence request with artistId:", currentArtistId, "and influencedById:", artistId);

                const influenceResponse = await fetch("http://localhost:8080/artist-influences", {
                    method: "POST",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({
                        artistId: currentArtistId,
                        influencedById: artistId,
                    }),
                });

                if (influenceResponse.ok) {
                    setSelectedCount((prev) => prev + 1);
                    console.log("Artist influence added successfully. Selected Count:", selectedCount + 1);
                    if (selectedCount + 1 === 3) {
                        navigateTo("userMain");
                    }
                } else {
                    console.error("Failed to add influence");
                }
            } catch (err) {
                console.error("Error adding influence", err);
            }
        };

        const encodeImagePath = (path) => {
            if (typeof path === "string" && path) {
                try {
                    const cleaned = path.replace(/\+/g, ' ');
                    const decoded = decodeURIComponent(cleaned);
                    const parts = decoded.split('/').map(part => encodeURIComponent(part));
                    const encodedPath = parts.join('/');
                    return `url(${encodedPath})`;
                } catch (err) {
                    console.error("Error encoding image path:", err);
                    return `url(${path})`;
                }
            }
            return "";
        };

        return (
            <div
                className="influences-container"
                style={{
                    backgroundImage: `url(${selectBackgroundImg})`,
                    backgroundSize: "cover",
                    backgroundPosition: "center",
                    minHeight: "100vh",
                    padding: "20px",
                    color: "white",
                }}
            >
                <h1 style={{ fontSize: "36px", fontWeight: "bold", marginBottom: "10px", color: "black" }}>
                    Pick 3 of your favourite artists
                </h1>
                <p style={{ marginBottom: "30px", color: "black" }}>Selected: {selectedCount}/3</p>

                {/* Genre buttons */}
                <div
                    style={{
                        display: "flex",
                        flexWrap: "wrap",
                        justifyContent: "center",
                        gap: "20px",
                        marginBottom: "40px",
                    }}
                >
                    {genres.map((genre) => (
                        <button
                            key={genre.id}
                            onClick={() => handleGenreClick(genre.id)}
                            style={{
                                backgroundImage: encodeImagePath(genre.imagePath),
                                backgroundSize: "cover",
                                backgroundPosition: "center",
                                width: "150px",
                                height: "150px",
                                borderRadius: "10px",
                                cursor: "pointer",
                                transition: "all 0.3s ease", // Smooth transition for hover
                                transform: selectedGenreId === genre.id ? "scale(0.95)" : "scale(1)", // Shrink when selected
                                border: selectedGenreId === genre.id ? "2px solid white" : "none", // White border when selected
                            }}
                        />
                    ))}
                </div>

                {/* Artist buttons */}
                {artists.filter(artist => artist.imagePath || artist.user?.imagePath).length > 0 && (
                    <div style={{ display: "flex", flexWrap: "wrap", justifyContent: "center", gap: "20px" }}>
                        {artists
                            .filter(artist => artist.imagePath || artist.user?.imagePath)
                            .map((artist, index) => {
                                const imagePath = artist.imagePath || artist.user?.imagePath;
                                const name = artist.fullName || "Unnamed Artist";

                                // Using userId as the key
                                const uniqueKey = artist.userId || index;
                                const isSelected = selectedArtistId === artist.userId;

                                return (
                                    <div key={uniqueKey} style={{ textAlign: "center" }}>
                                        <button
                                            onClick={() => handleArtistClick(artist.userId)}
                                            style={{
                                                backgroundImage: encodeImagePath(imagePath),
                                                backgroundSize: "cover",
                                                backgroundPosition: "center",
                                                width: "120px",
                                                height: "120px",
                                                borderRadius: "10px",
                                                border: isSelected ? "3px solid white" : "none", // White border when selected
                                                transform: isSelected ? "scale(0.95)" : "scale(1)", // Shrink when selected
                                                cursor: "pointer",
                                                transition: "all 0.3s ease", // Smooth transition
                                            }}
                                        />
                                        <p style={{ marginTop: "8px", color: "white", fontSize: "14px" }}>
                                            {name}
                                        </p>
                                    </div>
                                );
                            })}
                    </div>
                )}
            </div>
        );
    };



    const UserMainPage = () => {
        const [artistData, setArtistData] = useState(null);
        const fullName = userRepository.getFullName();

        useEffect(() => {
            const fetchArtistData = async () => {
                try {
                    const response = await fetch(`http://localhost:8080/users/fullName/${fullName}`);
                    const data = await response.json();

                    if (data.error) {
                        console.error(data.error);
                        return;
                    }

                    setArtistData(data);
                } catch (error) {
                    console.error('Error fetching artist data:', error);
                }
            };

            if (fullName) {
                fetchArtistData();
            } else {
                console.log('No full name found');
            }
        }, [fullName]);

        const handleLogout = () => {
            userRepository.clearUser();
            window.location.reload();
        };

        if (!artistData) {
            return <div>Loading artist details...</div>;
        }

        return (
            <div style={{ display: 'flex', height: '100vh', overflow: 'hidden' }}>
                {/* Sidebar */}
                <aside style={{ width: '220px', background: '#1c1c1c', color: '#fff', padding: '1rem' }}>
                    <h2 style={{ color: '#61dafb' }}>Menu</h2>
                    <ul style={{ listStyle: 'none', padding: 0 }}>
                        <li><button onClick={() => navigateTo("home")} style={navBtnStyle}>Home</button></li>
                        <li><button onClick={() => navigateTo("discovery")} style={navBtnStyle}>Search</button></li>
                        <li><button onClick={() => navigateTo("account")} style={navBtnStyle}>My Account</button></li>
                        <li><button onClick={() => navigateTo("login")} style={navBtnStyle}>Log Out</button></li>
                    </ul>
                </aside>


                {/* Main Area */}
                <main
                    style={{
                        flex: 1,
                        backgroundColor: '#121212',
                        color: '#fff',
                        display: 'flex',
                        flexDirection: 'column',
                        justifyContent: 'center',
                        alignItems: 'center',
                        textAlign: 'center',
                        backgroundImage: `url(${artistData.wallpaperPath || '/default-wallpaper.jpg'})`,
                        backgroundSize: 'cover',
                        backgroundPosition: 'center',
                        backgroundRepeat: 'no-repeat',
                        height: '100vh',
                    }}
                >
                    {/* Artist Image in the top right corner */}
                    <img
                        src={artistData.imagePath}
                        alt="Artist"
                        style={{
                            width: '150px',
                            height: '150px',
                            objectFit: 'cover',
                            borderRadius: '50%',
                            position: 'absolute',
                            top: '20px',
                            right: '20px',
                            border: '3px solid #fff',
                        }}
                    />

                    {/* Main Content */}
                    <div style={{ marginTop: '200px', zIndex: 1 }}>
                        <h1>{artistData.fullName}</h1>
                    </div>
                </main>
            </div>
        );
    };

    const navBtnStyle = {
        background: 'transparent',
        border: 'none',
        color: '#fff',
        padding: '0.5rem 1rem',
        cursor: 'pointer',
        fontSize: '1rem',
        textAlign: 'left',
        width: '100%',
        marginBottom: '0.5rem',
    };

  return (
    <BrowserRouter>
      <div>
        {currentPage === "home" && <Home />}
        {currentPage === "login" && <Login />}
        {currentPage === "about" && <About />}
        {currentPage === "contact" && <Contact />}
        {currentPage === "createAccount" && <CreateAccount />}
        {currentPage === "accountType" && <AccountType />}
        {currentPage === "genre" && <Genre />}
        {currentPage === "discovery" && <DiscoveryPage />}
        {currentPage === "artist" && <ArtistPage />}
          {currentPage === "userMain" && <UserMainPage />}
          {currentPage === "influences" && <InfluencesPage />}
      </div>
    </BrowserRouter>
  );
}

export default App;
